145	QEMU_PLUGIN_EXPORT int qemu_plugin_install(qemu_plugin_id_t id,
146	                                           const qemu_info_t *info,
147	                                           int argc, char **argv)
148	{
149	    (void) info;
150	    for (int i = 0; i < argc; i++) {
151	        g_auto(GStrv) tok = g_strsplit(argv[i], "=", 2);
152	        if (g_strcmp0(tok[0], "outfile") == 0 && tok[1]) {
153	            outfile_path = g_strdup(tok[1]);
154	        } else {
155	            fprintf(stderr, "hybrid_handoff: unknown option: %s\n", argv[i]);
156	            return -1;
157	        }
158	    }
159	    if (!outfile_path) {
160	        fputs("hybrid_handoff: outfile=PATH is required\n", stderr);
161	        return -1;
162	    }
163	
164	    vcpu_state = qemu_plugin_scoreboard_new(sizeof(VcpuRegs));
165	    qemu_plugin_register_vcpu_init_cb(id, vcpu_init);
166	    qemu_plugin_register_vcpu_tb_trans_cb(id, vcpu_tb_trans);
167	    return 0;
168	}
