120	// Restores x1..x31 and PC into the QEMU vCPU via the gdbstub at `port`,
121	// then continues. Caller is responsible for waitpid().
122	inline void restore_state_via_gdbstub(uint16_t port,
123	                                      const hybrid_state_v1& state)
124	{
125	  spdlog::info("hybrid handback: connecting to gdbstub on tcp::{}", port);
126	  const int fd = detail::connect_loopback(port, std::chrono::seconds(5));
127	  spdlog::info("hybrid handback: connected, restoring state");
128	  gdbstub::Session sess{fd};
129	
130	  for (unsigned i = 1; i < 32; ++i) {
131	    auto reply = sess.send_command(gdbstub::encode_p_body(i, state.gpr[i]));
132	    if (reply != "OK")
133	      throw std::runtime_error(
134	        "gdbstub: P packet for x" + std::to_string(i) + " replied " + reply);
135	  }
136	
137	  // RV64 GDB register layout: x0..x31 = 0..31, pc = 32.
138	  auto reply = sess.send_command(gdbstub::encode_p_body(32, state.pc));
139	  if (reply != "OK")
140	    throw std::runtime_error("gdbstub: P32 (pc) replied " + reply);
141	
142	  spdlog::info("hybrid handback: continuing target");
143	  sess.cont();
144	}
145	
146	// Top-level: spawns QEMU, restores state, waits for exit, returns exit
147	// status (or 128 + signal for abnormal termination).
148	inline auto run_qemu_handback(const std::string& qemu_binary,
149	                              const std::string& elf_path,
150	                              const hybrid_state_v1& state) -> int
151	{
152	  const auto port = detail::pick_free_port();
153	  spdlog::info("hybrid handback: spawning {} -gdb tcp::{} -S",
154	               qemu_binary, port);
155	  const pid_t pid = detail::spawn_qemu(qemu_binary, elf_path, port);
156	
157	  try {
158	    restore_state_via_gdbstub(port, state);
159	  } catch (...) {
160	    ::kill(pid, SIGKILL);
161	    int wstat = 0;
162	    ::waitpid(pid, &wstat, 0);
163	    throw;
164	  }
165	
166	  int wstat = 0;
167	  if (::waitpid(pid, &wstat, 0) < 0)
168	    throw std::runtime_error(std::string{"waitpid: "}
169	                             + std::strerror(errno));
170	  if (WIFEXITED(wstat)) return WEXITSTATUS(wstat);
171	  if (WIFSIGNALED(wstat)) return 128 + WTERMSIG(wstat);
172	  return -1;
173	}
