1	// GDB Remote Serial Protocol encoders/parsers for the vsim->QEMU resume
2	// path. The TCP transport is layered on top in hybrid/gdbstub_session.hpp.
3	//
4	// Only the subset needed for register restore is implemented:
5	//   - $body#cksum framing
6	//   - `P<reg>=<value>` write-register
7	//   - `c` continue
8	// Run-length-encoded responses (rare in modern stubs) are not handled.
9	
10	#pragma once
11	
12	#include <array>
13	#include <cstdint>
14	#include <optional>
15	#include <string>
16	#include <string_view>
17	
18	namespace hybrid::gdbstub
19	{
20	
21	inline auto compute_checksum(std::string_view body) -> uint8_t
22	{
23	  unsigned sum = 0;
24	  for (char c : body) sum += static_cast<unsigned char>(c);
25	  return static_cast<uint8_t>(sum & 0xFFu);
26	}
27	
28	namespace detail
29	{
30	
31	inline auto hex_nybble(unsigned v) -> char
32	{
33	  return static_cast<char>(v < 10 ? '0' + v : 'a' + (v - 10));
34	}
35	
36	inline void append_hex_byte(std::string& out, uint8_t b)
37	{
38	  out.push_back(hex_nybble((b >> 4) & 0xFu));
39	  out.push_back(hex_nybble(b & 0xFu));
40	}
41	
42	inline auto from_hex(char c) -> std::optional<unsigned>
43	{
44	  if (c >= '0' && c <= '9') return static_cast<unsigned>(c - '0');
45	  if (c >= 'a' && c <= 'f') return static_cast<unsigned>(c - 'a' + 10);
46	  if (c >= 'A' && c <= 'F') return static_cast<unsigned>(c - 'A' + 10);
47	  return std::nullopt;
48	}
49	
50	}  // namespace detail
51	
52	inline auto encode_packet(std::string_view body) -> std::string
53	{
54	  std::string out;
55	  out.reserve(body.size() + 4);
56	  out.push_back('$');
57	  out.append(body);
58	  out.push_back('#');
59	  detail::append_hex_byte(out, compute_checksum(body));
60	  return out;
61	}
62	
63	// Body of a `P<reg-hex>=<value-bytes-le-hex>` packet (no $...# framing).
64	// reg is the GDB register number (0..31 for GPR, 32 for pc on RV64).
65	// value is encoded as 8 little-endian bytes.
66	inline auto encode_p_body(unsigned reg_num, uint64_t value) -> std::string
67	{
68	  std::string body;
69	  body.push_back('P');
70	  if (reg_num < 16) {
71	    body.push_back(detail::hex_nybble(reg_num));
72	  } else {
73	    body.push_back(detail::hex_nybble((reg_num >> 4) & 0xFu));
74	    body.push_back(detail::hex_nybble(reg_num & 0xFu));
75	  }
76	  body.push_back('=');
77	  for (unsigned i = 0; i < 8; ++i) {
78	    detail::append_hex_byte(body, static_cast<uint8_t>(value & 0xFFu));
79	    value >>= 8;
80	  }
81	  return body;
82	}
83	
84	inline auto encode_p_packet(unsigned reg_num, uint64_t value) -> std::string
85	{
86	  return encode_packet(encode_p_body(reg_num, value));
87	}
88	
89	inline auto encode_continue() -> std::string
90	{
91	  return encode_packet("c");
92	}
93	
94	// Parses one $body#cksum frame and returns the body iff the checksum matches.
95	inline auto parse_packet(std::string_view raw) -> std::optional<std::string>
96	{
97	  if (raw.size() < 4 || raw.front() != '$') return std::nullopt;
98	  const auto hash = raw.find('#');
99	  if (hash == std::string_view::npos) return std::nullopt;
100	  if (raw.size() < hash + 3) return std::nullopt;
101	
102	  const auto body = raw.substr(1, hash - 1);
103	  const auto cs_hi = detail::from_hex(raw[hash + 1]);
104	  const auto cs_lo = detail::from_hex(raw[hash + 2]);
105	  if (!cs_hi || !cs_lo) return std::nullopt;
106	
107	  const auto expected = static_cast<uint8_t>((*cs_hi << 4) | *cs_lo);
108	  if (expected != compute_checksum(body)) return std::nullopt;
109	
110	  return std::string{body};
111	}
112	
113	}  // namespace hybrid::gdbstub
